#include<bits/stdc++.h>
using namespace std;
typedef unsigned long long ull;
int main()
{
    ull n,m,a,b,x,ans;
    scanf("%llu%llu%llu%llu%llu",&n,&m,&a,&b,&x);
    ans=n*m;
    if(x==0&&a%2==0)
    {
        n--;
    }
    if(x==0&&b%2==0)
    {
        m--;
    }
    if(x==1&&(a%2==1&&b%2==1&&n%2==1&&m%2==1))
    {
        ans++;
    }
    ans-=((n+1)/2)*((m+1)/2);
    printf("%llu",ans);
    return 0;
}
